        min: Optional['types.InvestmentMinAggregateInput'] = None,
        max: Optional['types.InvestmentMaxAggregateInput'] = None,
        having: Optional['types.InvestmentScalarWhereWithAggregatesInput'] = None,
        count: Optional[Union[bool, 'types.InvestmentCountAggregateInput']] = None,
